CREATE TABLE quant_metrics_to_technology_categories
(
	id serial,
	quant_metric_id integer NOT NULL,
	technology_category_id integer NOT NULL,

	CONSTRAINT pk_quant_metrics_to_technology_categories PRIMARY KEY(id)
	, CONSTRAINT fk_quant_metrics_to_technology_categories_quant_metric FOREIGN KEY (quant_metric_id) REFERENCES quant_metrics (id) MATCH SIMPLE ON UPDATE CASCADE ON DELETE CASCADE
	, CONSTRAINT fk_quant_metrics_to_technology_categories_technology_category FOREIGN KEY (technology_category_id) REFERENCES technology_categories (id) MATCH SIMPLE ON UPDATE CASCADE ON DELETE CASCADE
);
CREATE INDEX i_quant_metrics_to_technology_categories_quant_metric ON quant_metrics_to_technology_categories (quant_metric_id);
CREATE INDEX i_quant_metrics_to_technology_categories_technology_category ON quant_metrics_to_technology_categories (technology_category_id);
